// Compile the Morning Brief as TWO short, scannable messages (repo mounted read-only at /data/swingby):
//   1/2 Where we stand + overnight headlines · 2/2 Your moves today
// Trimmed 2026-07-17 per Kira ("works but more detailed than needed"): headline bullets only,
// hard caps everywhere, no raw build-log tail, no sub-steps — detail lives in STATUS.md /
// HUMAN-TODO.md and each message ends with that pointer. Voice per ~/brain/KIRA.md: decisions
// first, plain prose, never a log dump. Output sanitised (Markdown/Obsidian stripped,
// word-boundary clipping, Telegram HTML escaping on dynamic text only). Each item carries
// tokenVar so the two messages can post from different bots (falls back to TELEGRAM_BOT_TOKEN).
const fs = require('fs');
const read = (p) => { try { return fs.readFileSync(p, 'utf8'); } catch (e) { return ''; } };
const MEM = '/data/swingby/AGENTS/claude/memory/';

const status = read(MEM + 'STATUS.md');
const todo   = read(MEM + 'HUMAN-TODO.md');
const slog   = read(MEM + 'SESSION_LOG.md');
const doctor = read(MEM + 'DOCTOR-LATEST.md');

// --- text hygiene ------------------------------------------------------------
// Strip Markdown / Obsidian formatting down to plain prose.
const clean = (s) => (s || '')
  .replace(/`{1,3}([^`]*)`{1,3}/g, '$1')            // `code`
  .replace(/`/g, '')                                 // stray backticks
  .replace(/\*\*([^*]+)\*\*/g, '$1')                 // **bold**
  .replace(/\*([^*]+)\*/g, '$1')                     // *italic*
  .replace(/~~([^~]+)~~/g, '$1')                     // ~~strike~~
  .replace(/\[\[[^\]|]*\|([^\]]+)\]\]/g, '$1')       // [[target|label]] -> label
  .replace(/\[\[([^\]]+)\]\]/g, '$1')                // [[wikilink]] -> text
  .replace(/\[([^\]]+)\]\([^)]*\)/g, '$1')           // [label](url) -> label
  .replace(/^#{1,6}\s*/, '')                         // leading heading hashes
  .replace(/^\s*[-*]\s*\[[ xX]\]\s*/, '')            // checkbox marker
  .replace(/^\s*[-*•]\s+/, '')                       // leading list bullet
  .replace(/^\s*\d+\.\s+/, '')                       // leading "1. "
  .replace(/^\(([^)]{2,90})\)[\s:—–-]*/, '')          // leading "(tag)" label
  .replace(/\s*·\s*/g, ' — ')                        // middot separator -> em dash
  .replace(/[ \t]+/g, ' ')
  .trim();

// Escape for Telegram parse_mode=HTML. Apply ONLY to dynamic text, never to our own tags.
const esc = (s) => (s || '')
  .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

// Clip to n chars on a sentence, then word, boundary — never mid-word.
const clip = (s, n) => {
  s = (s || '').trim();
  if (s.length <= n) return s;
  const cut = s.slice(0, n);
  const stop = Math.max(cut.lastIndexOf('. '), cut.lastIndexOf('; '));
  if (stop > n * 0.55) return cut.slice(0, stop + 1).trim();
  return cut.replace(/\s+\S*$/, '').trim() + '…';
};

// One clean, escaped bullet (headline length by default — detail stays in the repo).
const bullet = (text, max) => '• ' + esc(clip(clean(text), max || 140));

// Body of a '## Heading' section ('###' subheadings stay inside).
const section = (src, heading, hashes) => {
  hashes = hashes || '##';
  const h = heading.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const m = new RegExp('^' + hashes + ' .*' + h + '.*$', 'm').exec(src);
  if (!m) return '';
  const rest = src.slice(m.index + m[0].length);
  const next = rest.search(new RegExp('^' + hashes + ' ', 'm'));
  return (next === -1 ? rest : rest.slice(0, next)).trim();
};

// Bodies of EVERY '## Heading' section whose title matches (HUMAN-TODO keeps several
// dated "This morning" sections — the newest still-open tasks live in the later ones).
const sectionsAll = (src, heading) => {
  const h = heading.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const re = new RegExp('^## .*' + h + '.*$', 'gm');
  const bodies = [];
  let m;
  while ((m = re.exec(src)) !== null) {
    const rest = src.slice(m.index + m[0].length);
    const next = rest.search(/^## /m);
    bodies.push((next === -1 ? rest : rest.slice(0, next)).trim());
  }
  return bodies.join('\n');
};

// Turn a section body into clean headline bullets (skips sub-headings and blank lines).
const toBullets = (body, max, cap) => {
  const out = [];
  for (let l of (body || '').split('\n')) {
    l = l.trim();
    if (!l || /^#{1,6}\s/.test(l)) continue;
    const c = clean(l);
    if (c.length < 3) continue;
    out.push(bullet(c, cap || 140));
    if (out.length >= (max || 4)) break;
  }
  return out;
};

// Unchecked "- [ ]" task headlines from a section. Done items and sub-steps are skipped —
// the message points at HUMAN-TODO.md for the full steps.
const taskItems = (body, max) => {
  const items = [];
  for (const raw of (body || '').split('\n')) {
    if (/^\s*[-*]\s*\[ \]/.test(raw)) {
      items.push(raw.trim());
      if (items.length >= (max || 4)) break;
    }
  }
  return items;
};

// Decisions get pulled to the top of the human message — Kira decides, never digs.
const isDecision = (t) => /decision|your call|decide/i.test(t);
const renderTasks = (arr, cap) => arr.map((t) => bullet(t, cap || 150)).join('\n');

// --- gather ------------------------------------------------------------------
const signal = section(status, 'Session End Signal');
const signalHead = clean((signal.split('\n')[0] || '').trim()) || 'No signal recorded — see STATUS.md';
const phase = clean((section(status, 'Current Phase').split('\n')[0] || '').trim());

// Doctor verdict: swingby_doctor.sh writes DOCTOR-LATEST.md after every session.
const doctorFails = (doctor || '').split('\n').filter((l) => l.includes('FAIL'));
const doctorLine = !doctor ? ''
  : doctorFails.length ? '🔴 <b>Health:</b> ' + doctorFails.length + ' problem(s) — see DOCTOR-LATEST.md'
  : '🟢 <b>Health:</b> all green';

// Preferred: an explicit '## Morning Brief' with '### Backend'/'### Frontend'/'### Recap'.
// Fallback: bucket the Session End Signal bullets by keyword (both/neither -> recap).
const mb = section(status, 'Morning Brief');
let backend = section(mb, 'Backend', '###');
let frontend = section(mb, 'Frontend', '###');
let recapBody = section(mb, 'Recap', '###');

if (!backend && !frontend) {
  const sLines = signal.split('\n');
  const bullets = sLines.filter((l) => /^\s*[-•]\s/.test(l));
  const isBack = (b) => /backend|fastapi|pytest|endpoint|\.py\b|supabase|migration|\bsql\b|render|stripe|conftest/i.test(b);
  const isFront = (b) => /mobile|frontend|screen|expo|babel|react|\bRN\b|gesture|navigation|App\.js|\.js\b|safearea/i.test(b);
  const back = [], front = [], rest = [];
  for (const b of bullets) {
    const bb = isBack(b), ff = isFront(b);
    if (bb && !ff) back.push(b);
    else if (ff && !bb) front.push(b);
    else rest.push(b);
  }
  backend = back.join('\n');
  frontend = front.join('\n');
  recapBody = rest.join('\n');
}

const todoAll     = taskItems(sectionsAll(todo, 'This morning'), 10);
const decisions   = taskItems(sectionsAll(todo, 'Decisions'), 5)
  .concat(todoAll.filter(isDecision)).slice(0, 3);
const doItems     = todoAll.filter((t) => !isDecision(t)).slice(0, 4);
const blockItems  = taskItems(sectionsAll(todo, 'Blocking'), 3);

const loopNext = clean((slog.match(/^NEXT:.*$/gm) || []).pop() || '');
const today = new Date().toLocaleDateString('en-CA', {
  timeZone: 'America/Edmonton', weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

// Join parts (keeping '' as blank-line spacers, dropping null), collapse runs of blank
// lines, then cap at a newline boundary (never splits a tag).
const build = (parts) => {
  const s = parts.filter((p) => p != null).join('\n')
    .replace(/\n{3,}/g, '\n\n')
    .replace(/^\n+|\n+$/g, '')
    .trim();
  if (s.length <= 3900) return s;
  const at = s.lastIndexOf('\n', 3900);
  return s.slice(0, at > 0 ? at : 3900).trim();
};

const backBullets  = toBullets(backend, 4);
const frontBullets = toBullets(frontend, 4);
const recapBullets = toBullets(recapBody, 3);

const messages = [
  {
    tokenVar: 'TELEGRAM_BOT_TOKEN_BACKEND',
    text: build([
      '☀️ <b>Morning, Kira</b> — 1/2 — ' + esc(today),
      '',
      '• ' + esc(clip(signalHead, 200)),
      phase ? '• 🎯 ' + esc(clip(phase, 120)) : null,
      doctorLine || null,
      '',
      '🔧 <b>Backend</b>',
      backBullets.length ? backBullets.join('\n') : '• Quiet night.',
      '',
      '📱 <b>Mobile</b>',
      frontBullets.length ? frontBullets.join('\n') : '• Quiet night.',
      recapBullets.length ? '' : null,
      recapBullets.length ? '🌙 <b>Also overnight</b>' : null,
      recapBullets.length ? recapBullets.join('\n') : null,
      loopNext ? '▶️ ' + esc(clip(loopNext.replace(/^NEXT:\s*/, ''), 140)) : null,
      '',
      '<i>Detail: STATUS.md</i>'
    ])
  },
  {
    tokenVar: 'TELEGRAM_BOT_TOKEN_HUMAN',
    text: build([
      '✅ <b>Your moves</b> — 2/2',
      '',
      decisions.length ? '🎯 <b>Decide — one line back is enough</b>' : null,
      decisions.length ? renderTasks(decisions) : null,
      decisions.length ? '' : null,
      '☑️ <b>Do this morning</b>',
      doItems.length ? renderTasks(doItems) : '• Nothing queued — enjoy the coffee. ☕',
      '',
      '⛔ <b>Blocked until you act</b>',
      blockItems.length ? renderTasks(blockItems) : '• Nothing is blocked. 🎉',
      '',
      '<i>Full steps: HUMAN-TODO.md</i>'
    ])
  }
];

return messages.map((m) => ({ json: m }));
